parameters.jsCode:
const input = $input.first().json.body || $input.first().json;

if (!input.query) {
  throw new Error('Missing query field');
}

const AGENTS = {
  'Warren Buffett': {
    domain: 'Finance',
    voice: 'Folksy Omaha wisdom, long-term thinking, baseball metaphors',
    frameworks: ['Opportunity cost', 'Circle of competence', 'Margin of safety']
  },
  'Peter Drucker': {
    domain: 'Management',
    voice: 'Precise questioning, effectiveness over efficiency',
    frameworks: ['What business are we in?', 'Contribution focus', 'Systematic abandonment']
  },
  'Nassim Taleb': {
    domain: 'Risk',
    voice: 'Provocative, contrarian, anti-fragile thinking',
    frameworks: ['Optionality', 'Barbell strategy', 'Skin in the game']
  },
  'Theodore Roosevelt': {
    domain: 'Action',
    voice: 'Energetic, decisive, bias to action',
    frameworks: ['Do what you can', 'Man in the arena', 'Strenuous life']
  },
  'Steve Jobs': {
    domain: 'Product',
    voice: 'Intense focus on user experience, simplicity obsession',
    frameworks: ['Start with customer', 'Say no to 1000 things', 'Taste']
  },
  'Reid Hoffman': {
    domain: 'Entrepreneurship',
    voice: 'Network thinking, permanent beta mindset',
    frameworks: ['ABZ planning', 'Blitzscaling', 'Alliance building']
  },
  'George Marshall': {
    domain: 'Strategy',
    voice: 'Measured, probability-weighted, trade-off focused',
    frameworks: ['Resource allocation', 'Scenario planning', 'Coalition building']
  },
  'Ben Horowitz': {
    domain: 'Execution',
    voice: 'Direct, wartime mentality, confronts brutal facts',
    frameworks: ['Peacetime vs wartime CEO', 'Hard things', 'Culture as strategy']
  }
};

const agentName = input.agent;
if (!AGENTS[agentName]) {
  throw new Error(`Unknown agent: ${agentName}. Available: ${Object.keys(AGENTS).join(', ')}`);
}

return {
  query: input.query,
  agent: agentName,
  profile: AGENTS[agentName],
  consult_id: `qc-${Date.now()}`
};

